def make_nodes(sid, prefix, acts, win_say):
    nodes = {}
    for ai, act in enumerate(acts, 1):
        next_bridge = f"{prefix}_a{ai+1}_bridge" if ai < 8 else f"{prefix}_win"
        bid = f"{prefix}_a{ai}_bridge"
        nodes[bid] = {"nodeId":bid,"type":"bridge","scenarioId":sid,"say":act[0],"hint":None,"visual":"nod","expectedKeywords":[],"minKeywordsRequired":1,"successNode":f"{prefix}_a{ai}_q1","retryNode":None,"failNode":None,"maxRetries":2,"isTerminal":False,"starValue":0}
        for si, step in enumerate(act[1], 1):
            say, kws, hint, teach = step[0], step[1], step[2], step[3]
            vis = step[4] if len(step) > 4 else "nod"
            nxt = f"{prefix}_a{ai}_q{si+1}" if si < 5 else next_bridge
            qid = f"{prefix}_a{ai}_q{si}"; rid = f"{prefix}_a{ai}_q{si}_r"; tid = f"{prefix}_a{ai}_q{si}_t"
            nodes[qid] = {"nodeId":qid,"type":"prompt","scenarioId":sid,"say":say,"hint":hint,"visual":vis,"expectedKeywords":kws,"minKeywordsRequired":1,"successNode":nxt,"retryNode":rid,"failNode":tid,"maxRetries":2,"isTerminal":False,"starValue":0}
            nodes[rid] = {"nodeId":rid,"type":"prompt","scenarioId":sid,"say":"No worries! Give it another try. "+say,"hint":hint,"visual":"nod","expectedKeywords":kws,"minKeywordsRequired":1,"successNode":nxt,"retryNode":tid,"failNode":tid,"maxRetries":1,"isTerminal":False,"starValue":0}
            nodes[tid] = {"nodeId":tid,"type":"teach","scenarioId":sid,"say":"No problem! You could say: "+teach+". Let's keep going.","hint":None,"visual":"point","expectedKeywords":[],"minKeywordsRequired":1,"successNode":nxt,"retryNode":None,"failNode":None,"maxRetries":2,"isTerminal":False,"starValue":0}
    wid = f"{prefix}_win"
    nodes[wid] = {"nodeId":wid,"type":"celebrate","scenarioId":sid,"say":win_say,"hint":None,"visual":"cheer","expectedKeywords":[],"minKeywordsRequired":1,"successNode":None,"retryNode":None,"failNode":None,"maxRetries":2,"isTerminal":True,"starValue":1}
    return nodes

